#include <iostream>

// 2. Use the standard C++ dictionary/namespace
using namespace std;

// 3. The main envelope where execution starts
int main() {
    
    // 4. Print the message to the screen. 
    // Notice the semicolon at the end!
    cout << "I am a C++ Master!" << endl;

    // 5. Return 0 to tell the OS everything was successful
    return 0;
    
} // Close the main envelope
